int cmpstr(const void* a,const void* b){ return strcmp(*(char**)a,*(char**)b); }
char* longestWord(char** words, int n) {
    qsort(words,n,sizeof(char*),cmpstr);
    char* ans = "";
    for(int i=0;i<n;i++){ int ok=1; int L=strlen(words[i]); for(int p=1;p<L&&ok;p++){ char pref[128]; strncpy(pref,words[i],p); pref[p]=0; ok=0; for(int j=0;j<n;j++) if(strcmp(words[j],pref)==0){ ok=1; break; } } if(ok && (L>(int)strlen(ans)||(L==(int)strlen(ans)&&strcmp(words[i],ans)<0))) ans=words[i]; }
    return ans;
}
